SELECT 
FROM bs_energy
WHERE deleted = 0

    AND enterprise_id = #{enterpriseId}


    AND name LIKE CONCAT('%', #{name}, '%')


    AND category = #{category}


    AND is_active = #{isActive}

ORDER BY category, id

